8	/// A simple stamped lock.
9	///
10	/// The state is represented as two `AtomicUsize`: `state_hi` for high bits and `state_lo` for low
11	/// bits.
12	pub(crate) struct SeqLock {
13	    /// The high bits of the current state of the lock.
14	    state_hi: AtomicUsize,
15	
16	    /// The low bits of the current state of the lock.
17	    ///
18	    /// All bits except the least significant one hold the current stamp. When locked, the state_lo
19	    /// equals 1 and doesn't contain a valid stamp.
20	    state_lo: AtomicUsize,
21	}
22	
23	impl SeqLock {
24	    pub(crate) const fn new() -> Self {
25	        Self {
26	            state_hi: AtomicUsize::new(0),
27	            state_lo: AtomicUsize::new(0),
28	        }
29	    }
30	
31	    /// If not locked, returns the current stamp.
32	    ///
33	    /// This method should be called before optimistic reads.
34	    #[inline]
35	    pub(crate) fn optimistic_read(&self) -> Option<(usize, usize)> {
36	        // The acquire loads from `state_hi` and `state_lo` synchronize with the release stores in
37	        // `SeqLockWriteGuard::drop`.
38	        //
39	        // As a consequence, we can make sure that (1) all writes within the era of `state_hi - 1`
40	        // happens before now; and therefore, (2) if `state_lo` is even, all writes within the
41	        // critical section of (`state_hi`, `state_lo`) happens before now.
42	        let state_hi = self.state_hi.load(Ordering::Acquire);
43	        let state_lo = self.state_lo.load(Ordering::Acquire);
44	        if state_lo == 1 {
45	            None
46	        } else {
47	            Some((state_hi, state_lo))
48	        }
49	    }
50	
51	    /// Returns `true` if the current stamp is equal to `stamp`.
52	    ///
53	    /// This method should be called after optimistic reads to check whether they are valid. The
54	    /// argument `stamp` should correspond to the one returned by method `optimistic_read`.
55	    #[inline]
56	    pub(crate) fn validate_read(&self, stamp: (usize, usize)) -> bool {
57	        // Thanks to the fence, if we're noticing any modification to the data at the critical
58	        // section of `(a, b)`, then the critical section's write of 1 to state_lo should be
59	        // visible.
60	        atomic::fence(Ordering::Acquire);
61	
62	        // So if `state_lo` coincides with `stamp.1`, then either (1) we're noticing no modification
63	        // to the data after the critical section of `(stamp.0, stamp.1)`, or (2) `state_lo` wrapped
64	        // around.
65	        //
66	        // If (2) is the case, the acquire ordering ensures we see the new value of `state_hi`.
67	        let state_lo = self.state_lo.load(Ordering::Acquire);
68	
69	        // If (2) is the case and `state_hi` coincides with `stamp.0`, then `state_hi` also wrapped
70	        // around, which we give up to correctly validate the read.
71	        let state_hi = self.state_hi.load(Ordering::Relaxed);
72	
73	        // Except for the case that both `state_hi` and `state_lo` wrapped around, the following
74	        // condition implies that we're noticing no modification to the data after the critical
75	        // section of `(stamp.0, stamp.1)`.
76	        (state_hi, state_lo) == stamp
77	    }
78	
79	    /// Grabs the lock for writing.
80	    #[inline]
81	    pub(crate) fn write(&'static self) -> SeqLockWriteGuard {
82	        let backoff = Backoff::new();
83	        loop {
84	            let previous = self.state_lo.swap(1, Ordering::Acquire);
85	
86	            if previous != 1 {
87	                // To synchronize with the acquire fence in `validate_read` via any modification to
88	                // the data at the critical section of `(state_hi, previous)`.
89	                atomic::fence(Ordering::Release);
90	
91	                return SeqLockWriteGuard {
92	                    lock: self,
93	                    state_lo: previous,
94	                };
95	            }
96	
97	            backoff.snooze();
98	        }
99	    }
100	}
