102	/// An RAII guard that releases the lock and increments the stamp when dropped.
103	pub(crate) struct SeqLockWriteGuard {
104	    /// The parent lock.
105	    lock: &'static SeqLock,
106	
107	    /// The stamp before locking.
108	    state_lo: usize,
109	}
