112	    /// Releases the lock without incrementing the stamp.
113	    #[inline]
114	    pub(crate) fn abort(self) {
115	        self.lock.state_lo.store(self.state_lo, Ordering::Release);
116	        mem::forget(self);
117	    }
118	}
