121	    #[inline]
122	    fn drop(&mut self) {
123	        let state_lo = self.state_lo.wrapping_add(2);
124	
125	        // Increase the high bits if the low bits wrap around.
126	        //
127	        // Release ordering for synchronizing with `optimistic_read`.
128	        if state_lo == 0 {
129	            let state_hi = self.lock.state_hi.load(Ordering::Relaxed);
130	            self.lock
131	                .state_hi
132	                .store(state_hi.wrapping_add(1), Ordering::Release);
133	        }
134	
135	        // Release the lock and increment the stamp.
136	        //
137	        // Release ordering for synchronizing with `optimistic_read`.
138	        self.lock.state_lo.store(state_lo, Ordering::Release);
139	    }
140	}
